export interface FetchProxyResponse {
  status: number;
  statusText: string;
  headers: Record<string, string>;
  body: string;
  ok: boolean;
}

export interface ToolHandlerContext {
  reportProgress(opts: ProgressOptions): void;
  fetchViaBackground(url: string, init?: RequestInit): Promise<FetchProxyResponse>;
}
```

2. `platform/browser-extension/src/tool-dispatch.ts` — in the MAIN world `func` passed to `chrome.scripting.executeScript` (around line 223), extend the context construction:
```typescript
let fetchCounter = 0;
const context = {
  reportProgress(opts) { /* existing code */ },
  fetchViaBackground(url, init) {
    return new Promise((resolve, reject) => {
      const requestId = dId + ':' + (fetchCounter++);
      const timeout = setTimeout(() => {
        document.removeEventListener(responseEvent, handler);
        reject(new Error('Fetch proxy timeout after 30s'));
      }, 30000);
      const responseEvent = 'opentabs:fetch-proxy:response:' + requestId;
      const handler = (e) => {
        clearTimeout(timeout);
        document.removeEventListener(responseEvent, handler);
        const detail = e.detail;
        if (detail.error) { reject(new Error(detail.error)); return; }
        resolve({ status: detail.status, statusText: detail.statusText, headers: detail.headers, body: detail.body, ok: detail.status >= 200 && detail.status < 300 });
      };
      document.addEventListener(responseEvent, handler);
      document.dispatchEvent(new CustomEvent('opentabs:fetch-proxy:request:' + dId, {
        detail: { requestId, url, method: init?.method || 'GET', headers: Object.fromEntries(new Headers(init?.headers).entries()), body: typeof init?.body === 'string' ? init.body : init?.body ? JSON.stringify(init.body) : undefined, pluginName: pName }
      }));
    });
  }
};
```

Note: The `func` parameter passed to `chrome.scripting.executeScript` must be self-contained — it cannot reference variables from the outer TypeScript scope. All types used inside the func must be inline (no imported types). The existing code at line 154-277 already follows this pattern.

The `pluginName` (pName) is already available as a parameter to the func. This is passed in the CustomEvent detail so the ISOLATED world relay can include it in the chrome.runtime.sendMessage, and the background handler can validate it.

Note on `context?` parameter: The handle() signature uses `context?: ToolHandlerContext`, meaning context is optional. The new `fetchViaBackground` method is always present when context is provided (which is always the case at runtime — the `?` is only for SDK-level type safety since the SDK doesn't know about the runtime context).
